#!/usr/bin/env node

import { readdir, readFile, stat, writeFile } from "node:fs/promises";
import path from "node:path";

const root = process.cwd();
const projectsRoot = path.join(root, "projects");
const outputPath = path.join(root, "meta", "projects-index.md");
const generatedNotice =
  "<!-- Generated from projects/*/project.md front matter by scripts/build-projects-index.mjs. Do not edit this file directly. -->";

function usage() {
  console.log(`Usage:
  node scripts/build-projects-index.mjs
  node scripts/build-projects-index.mjs --check

Options:
  --check   Validate that meta/projects-index.md is up to date without writing.
`);
}

function parseArgs(argv) {
  const args = new Set(argv);
  if (args.has("--help") || args.has("-h")) {
    usage();
    process.exit(0);
  }
  for (const arg of args) {
    if (arg !== "--check") {
      throw new Error(`Unknown option: ${arg}`);
    }
  }
  return { check: args.has("--check") };
}

async function pathExists(filePath) {
  try {
    await stat(filePath);
    return true;
  } catch (error) {
    if (error.code === "ENOENT") return false;
    throw error;
  }
}

async function listDirectories(dir) {
  if (!(await pathExists(dir))) return [];
  const entries = await readdir(dir, { withFileTypes: true });
  return entries
    .filter((entry) => entry.isDirectory() && !entry.name.startsWith("."))
    .map((entry) => entry.name)
    .sort();
}

function splitFrontmatter(markdown) {
  const match = markdown.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?/);
  if (!match) return { frontmatter: "", body: markdown };
  return { frontmatter: match[1], body: markdown.slice(match[0].length) };
}

function stripQuotes(value) {
  const trimmed = value.trim();
  const quoted = trimmed.match(/^"(.*)"$/) || trimmed.match(/^'(.*)'$/);
  return quoted ? quoted[1] : trimmed;
}

function parseInlineList(frontmatter, key) {
  const match = frontmatter.match(new RegExp(`^${key}:\\s*\\[(.*)\\]\\s*$`, "m"));
  if (!match) return [];
  return match[1]
    .split(",")
    .map((item) => stripQuotes(item))
    .filter(Boolean);
}

// Parse a YAML key whose value is either an inline list (`key: [a, b]`)
// or a block list:
//   key:
//     - a
//     - b
function parseList(frontmatter, key) {
  const inline = parseInlineList(frontmatter, key);
  if (inline.length) return inline;

  const lines = frontmatter.split(/\r?\n/);
  const startIndex = lines.findIndex((line) => new RegExp(`^${key}:\\s*$`).test(line));
  if (startIndex === -1) return [];

  const items = [];
  for (let i = startIndex + 1; i < lines.length; i += 1) {
    const itemMatch = lines[i].match(/^\s+-\s+(.*)$/);
    if (!itemMatch) break;
    const value = stripQuotes(itemMatch[1]);
    if (value) items.push(value);
  }
  return items;
}

function parseScalar(frontmatter, key) {
  const match = frontmatter.match(new RegExp(`^${key}:\\s*(.+)$`, "m"));
  if (!match) return "";
  return stripQuotes(match[1]);
}

function parseTitle(body) {
  const match = body.match(/^#\s+(.+)$/m);
  return match ? match[1].trim() : "";
}

function toPosixPath(value) {
  return value.split(path.sep).join("/");
}

function renderMarkdownLink(label, href) {
  return `[${label}](<${href.replaceAll(">", "%3E")}>)`;
}

// notes/<章節>/<檔名>.md -> <章節>
function chapterOfSourceNote(sourceNote) {
  const segments = toPosixPath(sourceNote).split("/");
  return segments.length >= 2 && segments[0] === "notes" ? segments[1] : "";
}

async function collectEntries() {
  const slugs = await listDirectories(projectsRoot);
  const entries = [];

  for (const slug of slugs) {
    const manifestPath = path.join(projectsRoot, slug, "project.md");
    if (!(await pathExists(manifestPath))) continue;

    const markdown = await readFile(manifestPath, "utf8");
    const { frontmatter, body } = splitFrontmatter(markdown);

    entries.push({
      slug,
      title: parseTitle(body) || slug,
      sourceNotes: parseList(frontmatter, "source_notes"),
      prerequisites: parseList(frontmatter, "prerequisites"),
      topics: parseList(frontmatter, "topics"),
      summary: parseScalar(frontmatter, "summary"),
      level: parseScalar(frontmatter, "level"),
      manifestRelPath: toPosixPath(path.join("..", "projects", slug, "project.md")),
    });
  }

  return entries;
}

function renderByProject(entries) {
  const lines = ["## 依專案瀏覽", ""];

  for (const entry of entries) {
    lines.push(`### ${renderMarkdownLink(entry.title, entry.manifestRelPath)}`, "");
    if (entry.level) lines.push(`- level: ${entry.level}`);
    if (entry.summary) lines.push(`- summary: ${entry.summary}`);
    if (entry.topics.length) lines.push(`- topics: ${entry.topics.join(", ")}`);
    if (entry.prerequisites.length) lines.push(`- prerequisites: ${entry.prerequisites.join(", ")}`);
    if (entry.sourceNotes.length) {
      lines.push("- source_notes:");
      for (const sourceNote of entry.sourceNotes) {
        lines.push(`  - ${toPosixPath(sourceNote)}`);
      }
    }
    lines.push("");
  }

  return lines;
}

// Reverse index: chapter -> projects whose source_notes touch it.
// Used by update-judgment to find projects affected by a chapter's notes change.
function renderByChapter(entries) {
  const lines = ["## 依來源章節反查", ""];
  const chapterMap = new Map();

  for (const entry of entries) {
    const chapters = new Set(entry.sourceNotes.map(chapterOfSourceNote).filter(Boolean));
    for (const chapter of chapters) {
      if (!chapterMap.has(chapter)) chapterMap.set(chapter, []);
      chapterMap.get(chapter).push(entry);
    }
  }

  const chapters = [...chapterMap.keys()].sort((a, b) => a.localeCompare(b, "zh-Hant"));
  if (!chapters.length) {
    lines.push("（目前尚無任何整合專案標記 source_notes）", "");
    return lines;
  }

  lines.push("某章 `notes/` 改動時，下列對應的整合專案需列為受影響下游候選重生成：", "");
  for (const chapter of chapters) {
    lines.push(`### ${chapter}`, "");
    for (const entry of chapterMap.get(chapter)) {
      lines.push(`- ${renderMarkdownLink(entry.title, entry.manifestRelPath)}`);
    }
    lines.push("");
  }

  return lines;
}

function renderIndex(entries) {
  const lines = [
    generatedNotice,
    "",
    "# Projects 索引",
    "",
    "> 本檔案由 `scripts/build-projects-index.mjs` 自動產生，請勿手動編輯。",
    "> 如需更新，請修改對應 `projects/<專案-slug>/project.md` 的 front matter 後重新執行：",
    ">",
    "> ```text",
    "> node scripts/build-projects-index.mjs",
    "> ```",
    "",
  ];

  if (!entries.length) {
    lines.push("（目前尚無任何整合專案）", "");
    return `${lines.join("\n").replace(/\n+$/, "")}\n`;
  }

  lines.push(...renderByProject(entries), ...renderByChapter(entries));

  return `${lines.join("\n").replace(/\n+$/, "")}\n`;
}

async function main() {
  const options = parseArgs(process.argv.slice(2));
  const entries = await collectEntries();
  const markdown = renderIndex(entries);

  if (options.check) {
    const current = (await pathExists(outputPath)) ? await readFile(outputPath, "utf8") : null;
    if (current !== markdown) {
      throw new Error(`${path.relative(root, outputPath)} is not up to date`);
    }
    console.log(`Checked ${path.relative(root, outputPath)}`);
    return;
  }

  await writeFile(outputPath, markdown);
  console.log(`Built ${path.relative(root, outputPath)} (${entries.length} projects)`);
}

main().catch((error) => {
  console.error(error.message);
  process.exit(1);
});
